const input = $input.first().json;
const body = input.body || {};

return [{ json: {
  query: body.query || input.query || 'test query',
  language: body.language || input.language || 'de',
  mode: body.mode || input.mode || 'standard',
  trigger_source: body.trigger_source || input.trigger_source || 'webhook',
  domain_hint: body.domain_hint || input.domain_hint || 'general',
  callback_webhook: body.callback_webhook || input.callback_webhook || '',
  user_id: body.user_id || input.user_id || '',
  run_id: body.run_id || input.run_id || ('run_' + Date.now()),
  cost: { total_tokens: 0, estimated_usd: 0, by_phase: {} }
} }];

const { execSync } = require('child_process');


const cliEnv = {
  HOME: '/home/clawd',
  PATH: '/home/clawd/.local/bin:/home/clawd/.npm-global/bin:/usr/local/bin:/usr/bin:/bin',
  GEMINI_API_KEY: $env.GEMINI_API_KEY || $env.GOOGLE_GEMINI_API_KEY || ''
};

const params = $('Set Parameters').first().json;
const query = params.query;
const language = params.language || 'de';
const mode = params.mode || 'standard';

const prompt = `Du bist ein Research-Planer. Zerlege diese Query in Suchbegriffe.\n\nQuery: \"${query}\"\nSprache: ${language}\nModus: ${mode}\n\nAntworte NUR mit validem JSON in diesem Format:\n{\n  \"original_query\": \"...\",\n  \"sub_queries\": [\"search term 1\", \"search term 2\", \"search term 3\"],\n  \"search_terms\": { \"primary_de\": \"...\", \"primary_en\": \"...\", \"counter_de\": \"...\", \"counter_en\": \"...\" },\n  \"domain\": \"tech|finance|academic|product_comparison|travel|general (choose best match for query)\",\n  \"expected_source_types\": [\"web\", \"academic\", \"news\"],\n  \"language\": \"${language}\"\n}\n\nKein Markdown, kein Kommentar, NUR JSON.`;

let stdout = '';
let stderr = '';
let exitCode = 0;
const maxRetries = 2;

for (let attempt = 0; attempt <= maxRetries; attempt++) {
  try {
    stdout = execSync(`gemini -m gemini-2.5-flash -p "${prompt.replace(/"/g, '\\\"')}"`, {
      encoding: 'utf-8',
      timeout: 120000,
      env: cliEnv
    });
    if (stdout.trim().length > 0) break;
  } catch (err) {
    stdout = err.stdout || '';
    stderr = err.stderr || '';
    exitCode = err.status || 1;
    if (stdout.trim().length > 0) break;
  }
  if (attempt < maxRetries) {
    execSync('sleep 2', { timeout: 5000 });
  }
}

return [{ json: { stdout: stdout.trim(), stderr: stderr.trim(), query, exitCode } }];

const geminiOutput = $input.first().json;
const params = $('Set Parameters').first().json;

let searchPlan;

try {
  let raw = geminiOutput.stdout || '';
  raw = raw.split('\n').filter(line => !line.match(/^(WARNING|ERROR|\[|Traceback)/i)).join('\n');
  const jsonMatch = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) raw = jsonMatch[1];
  const braceMatch = raw.match(/\{[\s\S]*\}/);
  if (braceMatch) {
    searchPlan = JSON.parse(braceMatch[0]);
  } else {
    throw new Error('Kein JSON gefunden');
  }
} catch (err) {
  searchPlan = {
    original_query: params.query,
    sub_queries: [params.query],
    search_terms: { primary_de: params.query, primary_en: params.query },
    domain: 'general',
    expected_source_types: ['web'],
    language: params.language
  };
}

if (!searchPlan.sub_queries || searchPlan.sub_queries.length === 0) {
  searchPlan.sub_queries = [params.query];
}
if (!searchPlan.search_terms) {
  searchPlan.search_terms = { primary_de: params.query, primary_en: params.query };
}

return [{ json: { search_plan: searchPlan, mode: params.mode, query: params.query, language: params.language } }];

const { execSync } = require('child_process');

const params = $('Set Parameters').first().json;
const query = params.query;
const mode = params.mode || 'standard';

if (mode === 'quick') return [{ json: { sources: [] } }];

const cliEnv = {
  HOME: '/home/clawd',
  PATH: '/home/clawd/.local/bin:/home/clawd/.npm-global/bin:/usr/local/bin:/usr/bin:/bin',
  PYTHONPATH: ''
};

let sources = [];
try {
  const result = execSync(`python3 /home/clawd/.openclaw/workspace/scripts/kb-search.py "${query.replace(/"/g, '\\"')}"`, {
    encoding: 'utf-8',
    timeout: 30000,
    env: cliEnv
  });

  const entryPattern = /\[(\d+)\]\s+score=([\d.]+)\s+\([^)]+\)\s+\|\s+(.+)/g;
  let match;
  const entries = [];
  while ((match = entryPattern.exec(result)) !== null) {
    entries.push({ score: parseFloat(match[2]), title: match[3].trim(), startPos: match.index });
  }
  for (let i = 0; i < entries.length; i++) {
    const entry = entries[i];
    const endPos = i + 1 < entries.length ? entries[i + 1].startPos : result.length;
    const block = result.substring(entry.startPos, endPos);
    const urlMatch = block.match(/URL:\s*(.+)/i);
    const snippetMatch = block.match(/Snippet:\s*(.+)/i);
    sources.push({
      url: urlMatch ? urlMatch[1].trim() : '',
      title: entry.title,
      snippet: snippetMatch ? snippetMatch[1].trim() : '',
      score: entry.score,
      source_type: 'kb',
      tier: 'T2'
    });
  }
} catch (err) {
  sources = [];
}

return [{ json: { sources } }];

const { execSync } = require('child_process');


const params = $('Set Parameters').first().json;
const plan = $('P0: Parse Search Plan').first().json.search_plan || {};
const query = params.query;

const searchTerms = [];
searchTerms.push(query);
if (plan.search_terms) {
  if (plan.search_terms.primary_de && plan.search_terms.primary_de !== query) searchTerms.push(plan.search_terms.primary_de);
  if (plan.search_terms.primary_en && plan.search_terms.primary_en !== query) searchTerms.push(plan.search_terms.primary_en);
}
if (plan.sub_queries) {
  for (const sq of plan.sub_queries.slice(0, 2)) {
    if (typeof sq === 'string' && sq !== query) searchTerms.push(sq);
  }
}

let allSources = [];
const seenUrls = new Set();

for (const term of searchTerms.slice(0, 3)) {
  const encodedQuery = encodeURIComponent(term);
  try {
    const braveKey = $env.BRAVE_SEARCH_API_KEY || $env.BRAVE_API_KEY || '';
    if (braveKey) {
      const braveResult = execSync(`curl -s -H "X-Subscription-Token: ${braveKey}" "https://api.search.brave.com/res/v1/web/search?q=${encodedQuery}&count=10"`, {
        encoding: 'utf-8', timeout: 15000
      });
      const braveData = JSON.parse(braveResult);
      if (braveData.web && braveData.web.results) {
        for (const r of braveData.web.results) {
          if (!seenUrls.has(r.url)) {
            seenUrls.add(r.url);
            allSources.push({ url: r.url, title: r.title || '', snippet: r.description || '', score: 0.7, source_type: 'web', origin: 'brave', tier: 'T3' });
          }
        }
      }
    }
  } catch (err) {}

  try {
    const tavilyKey = $env.TAVILY_API_KEY || '';
    if (tavilyKey) {
      const tavilyBody = JSON.stringify({ api_key: tavilyKey, query: term, max_results: 10, include_answer: false });
      const tavilyResult = execSync(`curl -s -X POST -H "Content-Type: application/json" -d '${tavilyBody.replace(/'/g, "'\\''")}'  "https://api.tavily.com/search"`, {
        encoding: 'utf-8', timeout: 15000
      });
      const tavilyData = JSON.parse(tavilyResult);
      if (tavilyData.results) {
        for (const r of tavilyData.results) {
          if (!seenUrls.has(r.url)) {
            seenUrls.add(r.url);
            allSources.push({ url: r.url, title: r.title || '', snippet: r.content || '', score: r.score || 0.6, source_type: 'web', origin: 'tavily', tier: 'T3' });
          }
        }
      }
    }
  } catch (err) {}

  if (allSources.length >= 15) break;
}

return [{ json: { sources: allSources } }];

const { execSync } = require('child_process');

const params = $('Set Parameters').first().json;
const query = params.query;

if (params.mode === 'quick') return [{ json: { sources: [] } }];


const minifluxUrl = $env.MINIFLUX_URL || 'http://localhost:8070';
const minifluxApiKey = $env.MINIFLUX_API_KEY || '';

if (!minifluxApiKey) return [{ json: { sources: [] } }];

const keywords = query.replace(/[^a-zA-Z\u00e4\u00f6\u00fc\u00c4\u00d6\u00dc\u00df0-9\s]/g, '').split(/\s+/).filter(w => w.length > 3);
const searchTerms = [query];
if (keywords.length >= 2) searchTerms.push(...keywords.slice(0, 3));

let sources = [];
const seenUrls = new Set();

for (const term of searchTerms) {
  try {
    const encodedTerm = encodeURIComponent(term);
    const result = execSync(`curl -s -H "X-Auth-Token: ${minifluxApiKey}" "${minifluxUrl}/v1/entries?search=${encodedTerm}&limit=10&order=published_at&direction=desc"`, {
      encoding: 'utf-8', timeout: 15000
    });
    const data = JSON.parse(result);
    if (data.entries && Array.isArray(data.entries)) {
      for (const entry of data.entries) {
        if (seenUrls.has(entry.url)) continue;
        seenUrls.add(entry.url);
        let snippet = (entry.content || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 500);
        sources.push({ url: entry.url || '', title: entry.title || '', snippet, source_type: 'rss', origin: 'miniflux', tier: 'T2' });
      }
    }
  } catch (err) {}
  if (sources.length >= 10) break;
}

if (sources.length === 0) {
  try {
    const result = execSync(`curl -s -H "X-Auth-Token: ${minifluxApiKey}" "${minifluxUrl}/v1/entries?limit=20&order=published_at&direction=desc&status=unread"`, {
      encoding: 'utf-8', timeout: 15000
    });
    const data = JSON.parse(result);
    if (data.entries && Array.isArray(data.entries)) {
      for (const entry of data.entries.slice(0, 5)) {
        let snippet = (entry.content || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 500);
        sources.push({ url: entry.url || '', title: entry.title || '', snippet, source_type: 'rss', origin: 'miniflux_recent', tier: 'T3' });
      }
    }
  } catch (err) {}
}

return [{ json: { sources } }];

const { execSync } = require('child_process');
const fs = require('fs');

const params = $('Set Parameters').first().json;
const plan = $('P0: Parse Search Plan').first().json.search_plan || {};
const query = params.query;
const language = params.language || 'de';

if (params.mode === 'quick') return [{ json: { sources: [] } }];


const cliEnv = {
  HOME: '/home/clawd',
  PATH: '/home/clawd/.local/bin:/home/clawd/.npm-global/bin:/usr/local/bin:/usr/bin:/bin',
  GEMINI_API_KEY: $env.GEMINI_API_KEY || $env.GOOGLE_GEMINI_API_KEY || ''
};

const subQueries = (plan.sub_queries || []).filter(sq => typeof sq === 'string').slice(0, 3);
const searchContext = subQueries.length > 0 ? `\nSub-Fragen: ${subQueries.join(', ')}` : '';

const prompt = `Recherchiere gruendlich zu: \"${query}\"${searchContext}\nSprache: ${language}\n\nFinde aktuelle Informationen. Fuer jede Quelle:\nSOURCE: [Titel]\nURL: [URL]\nFINDING: [Kernaussage]\n---`;

const tmpFile = '/tmp/gemini_deep_' + Date.now() + '.txt';
fs.writeFileSync(tmpFile, prompt);

let sources = [];
try {
  const result = execSync(`cat "${tmpFile}" | gemini -m gemini-2.5-pro -p "Process the above research request. For each source found, output in this exact format: SOURCE: [Title]\\nURL: [URL]\\nFINDING: [Key finding]\\n---"`, {
    encoding: 'utf-8', timeout: 240000, env: cliEnv, maxBuffer: 5 * 1024 * 1024
  });

  const blocks = result.split(/---+/);
  for (const block of blocks) {
    const titleMatch = block.match(/SOURCE:\s*(.+)/i);
    const urlMatch = block.match(/URL:\s*(https?:\/\/\S+)/i);
    const findingMatch = block.match(/FINDING:\s*(.+)/i);
    if (urlMatch) {
      sources.push({
        title: titleMatch ? titleMatch[1].trim() : 'Gemini Result',
        url: urlMatch[1].trim(),
        snippet: findingMatch ? findingMatch[1].trim() : '',
        score: 0.65, source_type: 'deep_search', origin: 'gemini', tier: 'T2'
      });
    }
  }

  if (sources.filter(s => s.url).length === 0 && result.length > 50) {
    const urlRegex = /https?:\/\/[^\s)\]>"',]+/g;
    const seenUrls = new Set();
    let match;
    while ((match = urlRegex.exec(result)) !== null) {
      let url = match[0].replace(/[.,;:!?)]+$/, '').replace(/\)+$/, '');
      if (seenUrls.has(url)) continue;
      seenUrls.add(url);
      const urlPos = result.indexOf(url);
      const before = result.substring(Math.max(0, urlPos - 300), urlPos);
      const titleLines = before.split(/\n/).filter(l => l.trim().length > 5);
      let title = titleLines.length > 0 ? titleLines[titleLines.length - 1].trim().replace(/^[\*\-\d.]+\s*/, '').replace(/\*+/g, '').trim() : 'Gemini Result';
      if (title.length > 120) title = title.substring(0, 120);
      sources.push({ title, url, snippet: '', score: 0.55, source_type: 'deep_search', origin: 'gemini_freetext', tier: 'T2' });
    }
  }
} catch (err) {
  sources.push({ title: 'ERROR: Gemini Deep Search', url: '', snippet: err.message || String(err), score: 0, source_type: 'error', origin: 'gemini_error', tier: 'T3' });
}

try { fs.unlinkSync(tmpFile); } catch(e) {}
return [{ json: { sources } }];

const { execSync } = require('child_process');

const params = $('Set Parameters').first().json;
const plan = $('P0: Parse Search Plan').first().json.search_plan || {};
const query = params.query;
const mode = params.mode || 'standard';

if (mode === 'quick') return [{ json: { sources: [] } }];

const searchTerm = (plan.search_terms && plan.search_terms.primary_en) || query;
const encodedQuery = encodeURIComponent(searchTerm);

let sources = [];
const seenTitles = new Set();

try {
  const ssResult = execSync(`curl -s "https://api.semanticscholar.org/graph/v1/paper/search?query=${encodedQuery}&limit=15&fields=title,abstract,url,citationCount,year,authors"`, {
    encoding: 'utf-8', timeout: 20000
  });
  const ssData = JSON.parse(ssResult);
  if (ssData.data) {
    for (const paper of ssData.data) {
      if (!paper.title || seenTitles.has(paper.title.toLowerCase())) continue;
      seenTitles.add(paper.title.toLowerCase());
      const authorStr = (paper.authors || []).slice(0, 3).map(a => a.name).join(', ');
      const citations = paper.citationCount || 0;
      let score = 0.6;
      if (citations > 100) score = 0.9;
      else if (citations > 20) score = 0.8;
      else if (citations > 5) score = 0.7;
      sources.push({
        url: paper.url || `https://api.semanticscholar.org/paper/${paper.paperId}`,
        title: paper.title,
        snippet: (paper.abstract || '').substring(0, 500),
        score,
        source_type: 'academic',
        origin: 'semantic_scholar',
        tier: citations > 20 ? 'T1' : 'T2',
        metadata: { authors: authorStr, year: paper.year, citations }
      });
    }
  }
} catch (err) {}

try {
  const arxivQuery = encodeURIComponent(searchTerm.replace(/[^a-zA-Z0-9\s]/g, ''));
  const arxivResult = execSync(`curl -s "http://export.arxiv.org/api/query?search_query=all:${arxivQuery}&max_results=10&sortBy=relevance"`, {
    encoding: 'utf-8', timeout: 20000
  });
  const entries = arxivResult.split('<entry>');
  for (const entry of entries.slice(1)) {
    const titleMatch = entry.match(/<title>([^<]+)<\/title>/);
    const summaryMatch = entry.match(/<summary>([^<]+)<\/summary>/);
    const idMatch = entry.match(/<id>([^<]+)<\/id>/);
    const publishedMatch = entry.match(/<published>([^<]+)<\/published>/);
    if (titleMatch && idMatch) {
      const title = titleMatch[1].trim().replace(/\s+/g, ' ');
      if (seenTitles.has(title.toLowerCase())) continue;
      seenTitles.add(title.toLowerCase());
      sources.push({
        url: idMatch[1].trim(),
        title,
        snippet: (summaryMatch ? summaryMatch[1].trim().replace(/\s+/g, ' ') : '').substring(0, 500),
        score: 0.65,
        source_type: 'academic',
        origin: 'arxiv',
        tier: 'T2',
        metadata: { published: publishedMatch ? publishedMatch[1].trim() : '' }
      });
    }
  }
} catch (err) {}

return [{ json: { sources } }];

const { execSync } = require('child_process');

const params = $('Set Parameters').first().json;
const query = params.query;
const mode = params.mode || 'standard';

if (mode === 'quick') return [{ json: { sources: [] } }];


const xaiKey = $env.XAI_API_KEY || $env.GROK_API_KEY || '';
if (!xaiKey) return [{ json: { sources: [] } }];

let sources = [];

try {
  const body = JSON.stringify({
    model: 'grok-4',
    messages: [{
      role: 'system',
      content: 'Search X/Twitter for recent discussions, opinions, and trends. Return structured results with post URLs, author handles, content summaries, and sentiment.'
    }, {
      role: 'user',
      content: `Find recent X/Twitter discussions about: ${query}. For each relevant post, provide: AUTHOR: @handle, CONTENT: summary, SENTIMENT: positive/negative/neutral, URL: link. Separate entries with ---`
    }],
    search_parameters: { mode: 'auto' }
  });

  const result = execSync(`curl -s -X POST -H "Content-Type: application/json" -H "Authorization: Bearer ${xaiKey}" -d '${body.replace(/'/g, "'\\''")}'  "https://api.x.ai/v1/chat/completions"`, {
    encoding: 'utf-8', timeout: 30000
  });

  const data = JSON.parse(result);
  const content = (data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content) || '';

  const blocks = content.split(/---+/);
  for (const block of blocks) {
    const authorMatch = block.match(/AUTHOR:\s*@?(\w+)/i);
    const contentMatch = block.match(/CONTENT:\s*(.+)/i);
    const sentimentMatch = block.match(/SENTIMENT:\s*(\w+)/i);
    const urlMatch = block.match(/URL:\s*(https?:\/\/\S+)/i);
    if (contentMatch) {
      sources.push({
        url: urlMatch ? urlMatch[1].trim() : (authorMatch ? `https://x.com/${authorMatch[1]}` : ''),
        title: authorMatch ? `@${authorMatch[1]} on X` : 'X/Twitter Discussion',
        snippet: contentMatch[1].trim().substring(0, 500),
        score: 0.5,
        source_type: 'social',
        origin: 'grok_x',
        tier: 'T3',
        metadata: { sentiment: sentimentMatch ? sentimentMatch[1].toLowerCase() : 'neutral' }
      });
    }
  }

  if (sources.length === 0 && content.length > 50) {
    sources.push({
      url: '',
      title: 'X/Twitter Discussion Summary',
      snippet: content.substring(0, 500),
      score: 0.4,
      source_type: 'social',
      origin: 'grok_x_summary',
      tier: 'T3'
    });
  }
} catch (err) {}

return [{ json: { sources } }];

const { execSync } = require('child_process');

const params = $('Set Parameters').first().json;
const query = params.query;
const mode = params.mode || 'standard';

if (mode !== 'deep') return [{ json: { sources: [] } }];


const youcomKey = $env.YOUCOM_API_KEY || '';
if (!youcomKey) return [{ json: { sources: [] } }];

let sources = [];

try {
  const encodedQuery = encodeURIComponent(query);
  const result = execSync(`curl -s -H "X-API-Key: ${youcomKey}" "https://api.ydc-index.io/research?query=${encodedQuery}"`, {
    encoding: 'utf-8', timeout: 60000
  });

  const data = JSON.parse(result);
  if (data.answer) {
    sources.push({
      url: '', title: 'You.com Research Summary', snippet: data.answer.substring(0, 1000),
      score: 0.7, source_type: 'deep_search', origin: 'youcom', tier: 'T2'
    });
  }
  if (data.citations) {
    for (const cite of data.citations) {
      sources.push({
        url: cite.url || '', title: cite.title || 'You.com Citation',
        snippet: (cite.snippet || cite.content || '').substring(0, 500),
        score: 0.65, source_type: 'deep_search', origin: 'youcom', tier: 'T2'
      });
    }
  }
} catch (err) {}

return [{ json: { sources } }];

const { execSync } = require('child_process');

const params = $('Set Parameters').first().json;
const query = params.query;
const mode = params.mode || 'standard';

if (mode !== 'deep') return [{ json: { sources: [] } }];


const exaKey = $env.EXA_API_KEY || '';
if (!exaKey) return [{ json: { sources: [] } }];

let sources = [];

try {
  const body = JSON.stringify({ query, num_results: 10, use_autoprompt: true, type: 'neural' });
  const result = execSync(`curl -s -X POST -H "Content-Type: application/json" -H "x-api-key: ${exaKey}" -d '${body.replace(/'/g, "'\\''")}'  "https://api.exa.ai/search"`, {
    encoding: 'utf-8', timeout: 20000
  });
  const data = JSON.parse(result);
  if (data.results) {
    for (const r of data.results) {
      sources.push({
        url: r.url || '', title: r.title || 'Exa Result',
        snippet: (r.text || r.highlights?.[0] || '').substring(0, 500),
        score: r.score || 0.6, source_type: 'deep_search', origin: 'exa', tier: 'T2'
      });
    }
  }
} catch (err) {}

return [{ json: { sources } }];

const items = $input.all();

let allSources = [];
for (const item of items) {
  if (item.json.sources && Array.isArray(item.json.sources)) {
    allSources = allSources.concat(item.json.sources);
  }
}

const seen = new Map();
const unique = [];

for (const src of allSources) {
  const url = (src.url || '').toLowerCase().replace(/\/+$/, '');
  if (!url || url === '') {
    unique.push(src);
    continue;
  }
  if (seen.has(url)) {
    const existing = seen.get(url);
    existing.score = Math.min(1.0, (existing.score || 0.5) + 0.15);
    existing.cross_referenced = true;
    if (existing.tier === 'T3') existing.tier = 'T2';
  } else {
    seen.set(url, src);
    unique.push(src);
  }
}

for (const src of unique) {
  if (!src.tier) {
    if (src.source_type === 'kb' || src.source_type === 'academic') src.tier = 'T2';
    else if (src.source_type === 'rss') src.tier = 'T2';
    else src.tier = 'T3';
  }
}

unique.sort((a, b) => (b.score || 0) - (a.score || 0));

const platforms = new Set(unique.map(s => s.origin || s.source_type));

const stats = {
  total_raw: allSources.length,
  total_sources: unique.length,
  unique_platforms: platforms.size,
  by_type: {
    kb: unique.filter(s => s.source_type === 'kb').length,
    web: unique.filter(s => s.source_type === 'web').length,
    rss: unique.filter(s => s.source_type === 'rss').length,
    deep_search: unique.filter(s => s.source_type === 'deep_search').length,
    academic: unique.filter(s => s.source_type === 'academic').length,
    social: unique.filter(s => s.source_type === 'social').length
  },
  by_tier: {
    T1: unique.filter(s => s.tier === 'T1').length,
    T2: unique.filter(s => s.tier === 'T2').length,
    T3: unique.filter(s => s.tier === 'T3').length
  }
};

return [{ json: { sources: unique, stats } }];

const data = $input.first().json;
const sources = data.sources || [];
const stats = data.stats || {};

const claims = [];
const seenClaims = new Set();

for (const src of sources) {
