const claimsData = $('P1: Extract Claims').first().json;
const params = $('Set Parameters').first().json;
const sources = claimsData.sources || [];
const runId = params.run_id;

let verificationData = {};
try { verificationData = $('P3: Verification').first().json.verification || {}; } catch(e) {}

let sql = 'BEGIN TRANSACTION;\n';

// Bookkeeping: bump run_count + last_seen for all sources (no audit event — pure metadata)
for (const src of sources.slice(0, 20)) {
  const srcUrl = src.url || '';
  if (!srcUrl) continue;
  const urlHash = srcUrl.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 100);
  sql += `UPDATE source_registry:\`${urlHash}\` SET run_count += 1, last_seen = time::now();\n`;
}

// Per-source reputation update with audit event.
// Two-statement split for the score formula because SurrealDB evaluates multi-SET
// expressions against PRE-update field values, and the legacy formula also did int division.
if (verificationData.cove && verificationData.cove.claims_checked > 0) {
  const inconsistencyRate = (verificationData.cove.inconsistencies_found || 0) / verificationData.cove.claims_checked;
  let evtType = null;
  let inc = null;
  if (inconsistencyRate <= 0.3) { evtType = 'correct'; inc = 'correct_count'; }
  else if (inconsistencyRate > 0.5) { evtType = 'incorrect'; inc = 'incorrect_count'; }
  if (evtType) {
    let i = 0;
    for (const src of sources.slice(0, 20)) {
      const srcUrl = src.url || '';
      if (!srcUrl) continue;
      const urlHash = srcUrl.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 100);
      sql += `LET $b${i} = (SELECT reputation_score, trust_level FROM source_registry:\`${urlHash}\`)[0];\n`;
      sql += `UPDATE source_registry:\`${urlHash}\` SET ${inc} += 1;\n`;
      sql += `UPDATE source_registry:\`${urlHash}\` SET reputation_score = (correct_count + 1.0) / (correct_count + incorrect_count + 2.0);\n`;
      sql += `LET $a${i} = (SELECT reputation_score, trust_level FROM source_registry:\`${urlHash}\`)[0];\n`;
      sql += `CREATE source_reliability_event CONTENT { source: source_registry:\`${urlHash}\`, event_type: '${evtType}', old_score: $b${i}.reputation_score, new_score: $a${i}.reputation_score, delta: $a${i}.reputation_score - $b${i}.reputation_score, trust_level_before: $b${i}.trust_level, trust_level_after: $a${i}.trust_level, run_id: research_run:\`${runId}\` };\n`;
      i++;
    }
  }
}

// Auto-promote: capture candidates -> bulk UPDATE -> emit events for each affected row
sql += `LET $promote = (SELECT id, reputation_score, trust_level FROM source_registry WHERE reputation_score >= 0.80 AND run_count >= 5 AND trust_level = 'T3');\n`;
sql += `UPDATE source_registry SET trust_level = 'T2' WHERE reputation_score >= 0.80 AND run_count >= 5 AND trust_level = 'T3';\n`;
sql += `FOR $row IN $promote { CREATE source_reliability_event CONTENT { source: $row.id, event_type: 'manual_override', old_score: $row.reputation_score, new_score: $row.reputation_score, delta: 0.0, trust_level_before: $row.trust_level, trust_level_after: 'T2', run_id: research_run:\`${runId}\` }; };\n`;

// Auto-downgrade: same pattern
sql += `LET $downgrade = (SELECT id, reputation_score, trust_level FROM source_registry WHERE reputation_score < 0.30 AND run_count >= 3 AND trust_level != 'untrusted');\n`;
sql += `UPDATE source_registry SET trust_level = 'untrusted' WHERE reputation_score < 0.30 AND run_count >= 3 AND trust_level != 'untrusted';\n`;
sql += `FOR $row IN $downgrade { CREATE source_reliability_event CONTENT { source: $row.id, event_type: 'manual_override', old_score: $row.reputation_score, new_score: $row.reputation_score, delta: 0.0, trust_level_before: $row.trust_level, trust_level_after: 'untrusted', run_id: research_run:\`${runId}\` }; };\n`;

sql += 'COMMIT TRANSACTION;\n';

return [{ json: { reputation_sql: sql } }];

