  });
  try {
    execSync(`curl -s -X POST "${callbackWebhook}" -H "Content-Type: application/json" -d '${payload}'`, { timeout: 10000 });
  } catch(e) { /* log but don't fail */ }
}

return [{ json: { run_id: runId, callback_sent: true, callback_webhook: callbackWebhook } }];
